using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Objecto que pode ser carregado e atirado pelo player (P6 — GrabThrowAbility):
/// caixas, pedras pequenas, o ovo da galinha (EggObject), etc.
///
/// O peso vem do ObjectWeight no mesmo GameObject (1 se não existir) e é
/// comparado com GrabThrowAbility.maxCarryWeight.
/// </summary>
[RequireComponent(typeof(Rigidbody2D), typeof(Collider2D))]
public class Carryable : MonoBehaviour
{
    [Tooltip("Eventos para feedback (sons/VFX) ao ser apanhado/largado.")]
    public UnityEvent onPickedUp;
    public UnityEvent onReleased;

    private Rigidbody2D _rb;
    private Collider2D[] _colliders;

    /// <summary>true enquanto está a ser carregado.</summary>
    public bool IsCarried { get; private set; }

    /// <summary>Peso de jogo (ObjectWeight; 1 se não existir).</summary>
    public float Weight
    {
        get
        {
            var ow = GetComponent<ObjectWeight>();
            return ow != null ? ow.weight : 1f;
        }
    }

    private void Awake()
    {
        _rb = GetComponent<Rigidbody2D>();
        _colliders = GetComponents<Collider2D>();
    }

    /// <summary>Chamado por GrabThrowAbility ao apanhar: prende ao "anchor" e desliga a física.</summary>
    public void OnPickedUp(Transform anchor)
    {
        IsCarried = true;

        _rb.linearVelocity = Vector2.zero;
        _rb.bodyType = RigidbodyType2D.Kinematic;

        foreach (var col in _colliders)
            col.enabled = false;

        transform.SetParent(anchor);
        transform.localPosition = Vector3.zero;

        onPickedUp?.Invoke();
    }

    /// <summary>Chamado por GrabThrowAbility ao largar/atirar: solta, religa a física e aplica "velocity".</summary>
    public void OnReleased(Vector2 position, Vector2 velocity)
    {
        IsCarried = false;

        transform.SetParent(null);
        transform.position = position;

        foreach (var col in _colliders)
            col.enabled = true;

        _rb.bodyType = RigidbodyType2D.Dynamic;
        _rb.linearVelocity = velocity;

        onReleased?.Invoke();
    }
}
